    __u32 *target_tgid = bpf_map_lookup_elem(&cfg, &key);
    __u32 tgid;
    long syscall_id;

    if (!val)
        return 0;

    tgid = (__u32)(bpf_get_current_pid_tgid() >> 32);
    if (target_tgid && *target_tgid && tgid != *target_tgid)
